const phrase = $('📥 Webhook Trigger').item.json.body.phrase || '';

const systemPrompt = `Eres un especialista en estrategia de YouTube Shorts para la marca "BeBetter Path". Tu objetivo es maximizar la retención y el alcance mediante títulos de alta curiosidad y descripciones optimizadas para SEO.

Se te dará una frase o concepto. Genera los metadatos en un objeto JSON puro.

REGLAS DE TONO:
- Voz: Mentor crudo, directo y autoritario. 
- Vocabulario permitido: Brutal, crudo, inevitable, disciplina, forjar, honor.
- Prohibido: Increíble, asombroso, genial, "click aquí".
- Lenguaje masculino y estoico.

REGLAS DE FORMATO:
- Título: Máximo 60 caracteres. Debe generar intriga o abordar un problema doloroso (Ej: "Por qué estás fracasando en..."). Sin emojis ni caracteres especiales: \\ / : * ? < > |
- Descripción: Un párrafo sólido (3-5 líneas) que use palabras clave (estoicismo, disciplina, mentalidad, éxito).
- Footer: Debe terminar EXACTAMENTE con el footer de marca y los hashtags técnicos.

Responde ÚNICAMENTE con este formato JSON:

{
  "title": "Título de alto impacto basado en la curiosidad",
  "description": "Cuerpo de la descripción enfocado en SEO y mentalidad.\n\nEl proceso no se negocia.\n@TheBeBetterPath ⚔️\n\n#TheBeBetterPath #Shorts #Estoicismo #Disciplina #Mentalidad",
  "tags": "bebetterpath,estoicismo,disciplina,mentalidad,shorts,crecimientopersonal,exito,filosofia,motivacion,autodisciplina"
}`;

const requestBody = {
  system_instruction: { parts: [{ text: systemPrompt }] },
  contents: [{ role: 'user', parts: [{ text: phrase }] }],
  generationConfig: { 
    temperature: 0.7,
    response_mime_type: "application/json"
  }
};

return [{ json: { requestBody: JSON.stringify(requestBody) } }];

const raw = $input.item.json.candidates?.[0]?.content?.parts?.[0]?.text || '';
let ytMeta;
try {
  const cleaned = raw.trim().replace(/^```json\s*/i, '').replace(/```\s*$/, '');
  ytMeta = JSON.parse(cleaned);
  if (!ytMeta.title || !ytMeta.description || !ytMeta.tags) throw new Error('Campos incompletos');
} catch(e) {
  const phrase = $('📥 Webhook Trigger').item.json.body.phrase || '';
  ytMeta = {
    title: phrase.slice(0, 60).replace(/[\/\\:*?"<>|]/g, '').trim(),
    description: 'El proceso no se negocia.\n@bebetter.path ⚔️\n\n#Shorts',
    tags: 'bebetter,motivacion,disciplina,estoicismo,shorts,mindset'
  };
}
if (!ytMeta.description.includes('#Shorts')) {
  ytMeta.description = ytMeta.description.trimEnd() + '\n\n#Shorts';
}
return [{ json: { ytTitle: ytMeta.title, ytDescription: ytMeta.description, ytTags: ytMeta.tags } }];

const item = $input.item;
const isError = !!(item.json.error || item.json.status === 'failed');
return [{ json: {
  platform: 'YouTube',
  status: isError ? 'ERROR' : 'SUCCESS',
  videoId: isError ? null : (item.json.id || null),
  errorDetails: isError ? (item.json.error?.message || JSON.stringify(item.json)) : null,
  timestamp: new Date().toISOString()
}}];

const phrase = $('📥 Webhook Trigger').item.json.body.phrase || '';

const systemPrompt = `Eres un copywriter experto en contenido de alto rendimiento y estoicismo para la marca "BeBetter Path" en Instagram. Tu voz es la de un mentor crudo, directo y autoritario que desprecia la comodidad.

Se te dará una frase o concepto. Tu función es generar el copy para la descripción del Reel.

Sigue este formato EXACTO:

[Frase corta, máximo 6 palabras, golpe al ego o curiosidad masiva]

[Párrafo 1: El problema. Describe una debilidad común de la sociedad o la trampa de la comodidad, 2-3 líneas]

[Párrafo 2: La verdad. La solución estoica o la realidad cruda que el espectador debe aceptar, 2-3 líneas]

[Párrafo 3: Acción. Un llamado a la disciplina interna y a la ejecución inmediata, 2-3 líneas]

[Parrafo 4: El proceso no se negocia.
@bebetter.path ⚔️]

REGLAS OBLIGATORIAS:
- Lenguaje masculino, fuerte y seco.
- NO incluyas hashtags.
- NO uses lenguaje motivacional barato o "mágico".
- Prohibidas: increíble, asombroso, mágico, extraordinario, dale like, suscríbete.
- Permitidas: brutal, crudo, inevitable, deuda, disciplina, proceso, forjar.
- Solo se permite el emoji de la espada (⚔️) al final.
- Responde ÚNICAMENTE con el copy resultante.`;

const requestBody = {
  system_instruction: { parts: [{ text: systemPrompt }] },
  contents: [{ role: 'user', parts: [{ text: phrase }] }],
  generationConfig: { 
    temperature: 0.8,
    top_p: 0.9
  }
};

return [{ json: { requestBody: JSON.stringify(requestBody) } }];

const caption = $input.item.json.candidates?.[0]?.content?.parts?.[0]?.text || '';
const phrase = $('📥 Webhook Trigger').item.json.body.phrase || '';
return [{ json: { message1: phrase, message2: caption } }];
